// The ensures is `LHS ==> det_init_equal(...)`. The prior attempt failed
// because at the top of the proof body the LHS (`post1_self_.wf()`, the two
// `is_empty()` foralls, etc.) is NOT in scope — only the function's
// `requires` are. Wrap the whole obligation in `assert(LHS ==> RHS) by { ... }`
// and pull the LHS into scope via `if LHS { ... }` so we can prove RHS
// with all four conjuncts available.
assert(({
    &&& (post1_self_.wf())
    &&& (forall|i: int| #![trigger post1_self_@[i].is_empty()] 0 <= i < 512 ==> post1_self_@[i].is_empty())
    &&& (post2_self_.wf())
    &&& (forall|i: int| #![trigger post2_self_@[i].is_empty()] 0 <= i < 512 ==> post2_self_@[i].is_empty())
}) ==> det_init_equal(r1, r2, post1_self_@, post2_self_@)) by {
    if post1_self_.wf()
        && (forall|i: int| #![trigger post1_self_@[i].is_empty()] 0 <= i < 512 ==> post1_self_@[i].is_empty())
        && post2_self_.wf()
        && (forall|i: int| #![trigger post2_self_@[i].is_empty()] 0 <= i < 512 ==> post2_self_@[i].is_empty())
    {
        // Lengths come from `.wf()`.
        assert(post1_self_@.len() == 512);
        assert(post2_self_@.len() == 512);

        // Pointwise: at every index both entries are `is_empty()`, which
        // pins every field (addr == 0 and the five perm booleans all
        // false), so the two `PageEntry`s are structurally equal.
        assert forall|i: int| 0 <= i < 512 implies post1_self_@[i] == post2_self_@[i] by {
            // Trigger both foralls at this `i`.
            assert(post1_self_@[i].is_empty());
            assert(post2_self_@[i].is_empty());
            // Unfold the open `is_empty()` definition for both sides.
            assert(post1_self_@[i].addr == 0);
            assert(post2_self_@[i].addr == 0);
            assert(post1_self_@[i].perm.present == false);
            assert(post2_self_@[i].perm.present == false);
            assert(post1_self_@[i].perm.ps == false);
            assert(post2_self_@[i].perm.ps == false);
            assert(post1_self_@[i].perm.write == false);
            assert(post2_self_@[i].perm.write == false);
            assert(post1_self_@[i].perm.execute_disable == false);
            assert(post2_self_@[i].perm.execute_disable == false);
            assert(post1_self_@[i].perm.user == false);
            assert(post2_self_@[i].perm.user == false);
            // All five perm fields agree -> perms are equal as structs.
            assert(post1_self_@[i].perm == post2_self_@[i].perm);
            // Both fields of PageEntry agree -> entries are equal.
        }

        // Lift pointwise equality to sequence extensionality.
        assert(post1_self_@ =~= post2_self_@);

        // Unit values are trivially equal.
        assert(r1 == r2);

        // Conclude: det_init_equal unfolds to (r1 == r2) && (s1 =~= s2).
        assert(det_init_equal(r1, r2, post1_self_@, post2_self_@));
    }
}
